// The postcondition of `det_set` is the implication
//   (A) ==> det_set_equal(r1, r2, post1_self_, post2_self_)
// where A is the conjunction of the `set` ensures clauses for both runs:
//   post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out)  &  post1_self_.wf()
//   post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)  &  post2_self_.wf()
//
// A is the antecedent of the ensures-implication, NOT a free body hypothesis,
// so a bare `assert(post1_self_.seq@ =~= ...)` at the top of the body would
// be unprovable from the requires alone (this is exactly what makes the
// underlying z3 query `unknown`). The fix is to discharge the implication
// directly via `assert(A ==> det_set_equal(...)) by { if A { ... } }`: inside
// the `if`-branch, every conjunct of A becomes a hypothesis, which lets us
// line up the two `=~=` quantifier instantiations on the shared term
// `pre_self_.seq@.update(i as int, out)` (the trigger gap the file-level
// query suffered from) and lift transitively to view-equality of the two
// post-states.
assert(({
    &&& (post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post1_self_.wf())
    &&& (post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out))
    &&& (post2_self_.wf())
}) ==> det_set_equal(r1, r2, post1_self_, post2_self_)) by {
    if post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
        && post1_self_.wf()
        && post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out)
        && post2_self_.wf()
    {
        // Re-state each ensures-conjunct so the two Seq-extensionality
        // (`=~=`) triggers fire on the common skolem
        // `pre_self_.seq@.update(i as int, out)`. This closes the
        // quantifier-instantiation gap that produced z3 `unknown`.
        assert(post1_self_.seq@ =~= pre_self_.seq@.update(i as int, out));
        assert(post2_self_.seq@ =~= pre_self_.seq@.update(i as int, out));

        // Both views collapse to a single sequence via Seq extensionality.
        assert(post1_self_.seq@ =~= post2_self_.seq@);
        assert(post1_self_.seq@ == post2_self_.seq@);

        // The `seq` field of `Array<A, N>` is `Ghost<Seq<A>>`; Ghost equality
        // reduces to equality of the inner `Seq<A>`, which we just established.
        assert(post1_self_.seq == post2_self_.seq);

        // Lengths are pinned in both runs.
        assert(post1_self_.seq@.len() == N);
        assert(post2_self_.seq@.len() == N);
        assert(post1_self_.seq@.len() == post2_self_.seq@.len());

        // Pointwise: at every valid index, both runs agree.
        assert forall|j: int| 0 <= j < N implies
            post1_self_.seq@[j] == post2_self_.seq@[j] by {
            // Both `=~=` ensures pin `seq@[j]` to `pre_self_.seq@.update(i as int, out)[j]`.
        }

        // r1 and r2 are unit tuples; equality is trivial.
        assert(r1 == r2);
    }
};
